class Solution:
    def is_valid_string(self, s: str) -> bool:
        left = right = 0
        while right < len(s):
            if s[right].isalnum() or s[right] in ['_', '-']:
                if left == right:
                    left += 1
                    right += 1
                else:
                    left = right
                    right += 1
            else:
                return False
        return True


